18	const BASE_PREMIUMS: Record<string, number> = {
19	  sword: 100,
20	  amulet: 60,
21	  staff: 80,
22	  potion: 40,
23	  rune: 25,
24	  moonstone: 25,
25	};
26	
27	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
28	const PROCESSING_FEE = 5;
29	
30	const BLOCK_SIZE = 3;
31	const BLOCK_BASE_PREMIUM = 60;
32	
33	const CURSE_SURCHARGE_RATE = 0.5;
34	
35	const ENCHANTMENT_SURCHARGE_RATE = 0.3;
36	const ENCHANTMENT_SURCHARGE_THRESHOLD = 5;
37	
38	const countItemsByType = (items: Item[]): Map<string, number> => {
39	  const counts = new Map<string, number>();
40	  for (const item of items) {
41	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
42	  }
43	  return counts;
44	};
45	
46	const basePremiumForGroup = (type: string, count: number): number =>
47	  count === BLOCK_SIZE ? BLOCK_BASE_PREMIUM : count * BASE_PREMIUMS[type];
48	
49	const calculateTotalBasePremium = (items: Item[]): number =>
50	  [...countItemsByType(items)].reduce(
51	    (total, [type, count]) => total + basePremiumForGroup(type, count),
52	    0,
53	  );
54	
55	const curseSurchargeForItem = (item: Item): number =>
56	  item.cursed ? BASE_PREMIUMS[item.type] * CURSE_SURCHARGE_RATE : 0;
57	
58	const enchantmentSurchargeForItem = (item: Item): number =>
59	  (item.enchantment ?? 0) >= ENCHANTMENT_SURCHARGE_THRESHOLD
60	    ? BASE_PREMIUMS[item.type] * ENCHANTMENT_SURCHARGE_RATE
61	    : 0;
62	
63	const sumSurcharges = (
64	  items: Item[],
65	  surchargeForItem: (item: Item) => number,
66	): number =>
67	  items.reduce((total, item) => total + surchargeForItem(item), 0);
68	
69	const LOYALTY_DISCOUNT_RATE = 0.2;
70	const LOYALTY_DISCOUNT_THRESHOLD_YEARS = 2;
71	
72	const quoteStep = (
73	  step: Step,
74	  customer: { yearsWithMHPCO: number },
75	): StepResult => {
76	  const totalBasePremium = calculateTotalBasePremium(step.items);
77	  const firstInsuranceSurcharge =
78	    totalBasePremium * FIRST_INSURANCE_SURCHARGE_RATE;
79	  const curseSurcharge = sumSurcharges(step.items, curseSurchargeForItem);
80	  const enchantmentSurcharge = sumSurcharges(
81	    step.items,
82	    enchantmentSurchargeForItem,
83	  );
84	  const loyaltyDiscount =
85	    customer.yearsWithMHPCO >= LOYALTY_DISCOUNT_THRESHOLD_YEARS
86	      ? totalBasePremium * LOYALTY_DISCOUNT_RATE
87	      : 0;
88	  return {
89	    premium: Math.ceil(
90	      totalBasePremium + curseSurcharge + enchantmentSurcharge +
91	        firstInsuranceSurcharge - loyaltyDiscount + PROCESSING_FEE,
92	    ),
93	  };
94	};
95	
96	export const processScenario = (scenario: Scenario): ScenarioResult => ({
97	  results: scenario.steps.map((step) => quoteStep(step, scenario.customer)),
98	});
